import React,{ useNavigate } from "react-router-dom";
import axios from "axios";
import { use } from "react";

function Register() {
    const[user,setUser] = useState({
        id:"",
        name:"",
        email:"",
        password:""
    });

    const {name, email, password} = user;

    const onInputChange = (e) => {
        setUser({...user, [e.target.name]: e.target.value});
    };

    const onSubmit = async (e) => {
        e.preventDefault();

        try {
            await axios.post("http://localhost:8080/user", user);
            alert("Registration successful!");
            //navigate("/"); // navigate to home after successful registration

            setUser({
                name:"",
                email:"",
                password:""
            });
        
        }catch (error) {
            console.error(error);
            alert("Registration failed. Please try again.");
        }
    }
  //const navigate = useNavigate(); // you can use this later for navigation after registration

  return (
    <div style={{ maxWidth: "500px", margin:"20px auto" }}>
        <h1>Register</h1>

        <form onSubmit={onSubmit}>

            <div className="form-group">
                <label htmlFor="name">Username</label><br/>
                <input type="text" id="name" name="name" value={name} onChange={onInputChange} required />
            </div>
    
            <div className="form-group">
                <label htmlFor="email">Email</label><br/>
                <input type="email" id="email" name="email" value={email} onChange={onInputChange} required />
            </div>

            <div className="form-group">
                <label htmlFor="password">Password</label><br/>
                <input type="password" id="password" name="password" value={password} onChange={onInputChange} required />
            </div>

            <button type="submit">Register</button>
        </form>
    </div>
  );
}

export default Register;
